import { Lenz } from "lenz-io";

const client = new Lenz();  // no api_key needed
const page = await client.library.listLibrary({ page: 1, sort: "recent" });
page.items.forEach(v => console.log(v.claim, "→", v.verdict.label));

import { Lenz } from "lenz-io";

const client = new Lenz({ apiKey: "lenz_..." });
const v = await client.verifyAndWait({ claim: "Sharks don't get cancer" });
console.log(v.verdict.label, v.verdict.score);
// false 2.0

import { Lenz } from "lenz-io";

const client = new Lenz({ apiKey: "lenz_..." });
const batch = await client.verifyBatch({
  claims: [
    { text: "The Eiffel Tower is in Berlin." },
    { text: "Water boils at 100°C at sea level." },
  ],
});
batch.items.forEach(i => console.log(i.taskId, i.claimText));

import { Lenz } from "lenz-io";

const client = new Lenz({ apiKey: "lenz_..." });
const out = await client.extract({
  text: "Coffee causes cancer and the earth is flat.",
});
out.identifiedClaims.forEach(c => console.log(c));

import { Lenz } from "lenz-io";

const client = new Lenz({ apiKey: "lenz_..." });
const s = await client.getStatus("tsk_abc123");
console.log(s.status);

import { Lenz } from "lenz-io";

const client = new Lenz({ apiKey: "lenz_..." });
const u = await client.account.getUsage();
console.log(`${u.creditsUsed} / ${u.creditsTotal}`);

import { Lenz } from "lenz-io";

const client = new Lenz({ apiKey: "lenz_..." });
const page = await client.verifications.listVerifications({ page: 1 });
page.items.forEach(v => console.log(v.verificationId, v.verdict.label));

import { Lenz } from "lenz-io";

const client = new Lenz({ apiKey: "lenz_..." });
const related = await client.verifications.related("vid_abc123", { limit: 5 });
related.items.forEach(r => console.log(r.verification_id, r.claim, r.verdict_label));
